import{_ as a,o as e,c as r,ae as o}from"./chunks/framework.Czhw_PXq.js";const d=JSON.parse('{"title":"Structural Alpha Theory v2.3","description":"","frontmatter":{},"headers":[],"relativePath":"strategy/structural-alpha.md","filePath":"strategy/structural-alpha.md"}'),l={name:"strategy/structural-alpha.md"};function s(n,t,u,i,c,h){return e(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="structural-alpha-theory-v2-3" tabindex="-1">Structural Alpha Theory v2.3 <a class="header-anchor" href="#structural-alpha-theory-v2-3" aria-label="Permalink to &quot;Structural Alpha Theory v2.3&quot;">​</a></h1><p><strong>&quot;알파는 단순히 좋은 신호에서 나오는 것이 아니라, 확보된 자본의 &#39;재배정(Re-allocation)&#39;에서 완성됩니다.&quot;</strong> - WeJump Labs</p><hr><h2 id="🏗️-1-구조적-알파의-정수-essence" tabindex="-1">🏗️ 1. 구조적 알파의 정수 (Essence) <a class="header-anchor" href="#🏗️-1-구조적-알파의-정수-essence" aria-label="Permalink to &quot;🏗️ 1. 구조적 알파의 정수 (Essence)&quot;">​</a></h2><p>CBVR v2.3에서 정의하는 **&#39;구조적 알파(Structural Alpha)&#39;**는 단순히 시장의 비효율을 찾는 것을 넘어, <strong>자본 구조의 설계</strong> 자체에서 초과 수익을 창출하는 금융공학적 접근입니다.</p><h3 id="⚙️-선물-복제-futures-replication-자본의-해방" tabindex="-1">⚙️ 선물 복제 (Futures Replication): 자본의 해방 <a class="header-anchor" href="#⚙️-선물-복제-futures-replication-자본의-해방" aria-label="Permalink to &quot;⚙️ 선물 복제 (Futures Replication): 자본의 해방&quot;">​</a></h3><ul><li><strong>핵심:</strong> KOSPI 200/NASDAQ 선물을 활용하여 목표 지수 노출도(Beta)를 단 15% 내외의 증거금으로 복제합니다.</li><li><strong>결과:</strong> 전체 가용 자본의 **70~80%가 유휴 유동성(Excess Liability)**으로 확보됩니다.</li></ul><h3 id="📈-bucket-3-realized-compounding-복리-실물화" tabindex="-1">📈 Bucket-3: Realized Compounding (복리 실물화) <a class="header-anchor" href="#📈-bucket-3-realized-compounding-복리-실물화" aria-label="Permalink to &quot;📈 Bucket-3: Realized Compounding (복리 실물화)&quot;">​</a></h3><ul><li><strong>알파의 발현:</strong> 해방된 잉여 현금을 <strong>Bucket-3</strong>로 이동시켜 안정적인 실물 자산(PFIX, 채권, 배당주 등)에 재투자합니다.</li><li><strong>이중 복리:</strong> 코어 엔진의 매매 수익과 Bucket-3의 안정적 현금 흐름이 결합되어, 일반적인 인덱스 추종 전략으로는 절대 도달할 수 없는 **&#39;구조적 초과 수익&#39;**을 만들어냅니다.</li></ul><hr><h2 id="📉-2-왜-v2-3인가" tabindex="-1">📉 2. 왜 v2.3인가? <a class="header-anchor" href="#📉-2-왜-v2-3인가" aria-label="Permalink to &quot;📉 2. 왜 v2.3인가?&quot;">​</a></h2><p>전략 코어 로직(v1.0)에 **자본 공학(v2.3)**이 결합되었을 때 비로소 위점프만의 독보적인 알파가 완성됩니다.</p><ul><li><strong>v1.0:</strong> 신호 센싱을 통한 시장 국면 판별 (Alpha Signal).</li><li><strong>v2.3:</strong> 선물 복제와 3-Bucket 시스템을 통한 <strong>자본 효율성 극대화 (Structural Alpha)</strong>.</li></ul><blockquote><p><strong>Key Insight:</strong> &quot;우리는 단순히 주식을 잘 사는 것이 아니라, **자본을 가장 똑똑하게 배치(Placement)**하여 시장보다 앞서 나갑니다.&quot; 🐯🐾</p></blockquote>',14)])])}const g=a(l,[["render",s]]);export{d as __pageData,g as default};
